import { Server } from 'socket.io';
import { Server as HttpServer } from 'http';

export interface MigrationOptions { announceUrl?: string; gracePeriodMs: number; }

export async function migrateColor(io: Server, httpServer: HttpServer, opts: MigrationOptions): Promise<void> {
  httpServer.close();
  io.emit('server:migrate', { reason: 'BLUE_GREEN_HANDOVER', newUrl: opts.announceUrl, reconnectAfterMs: 500 });

  const start = Date.now();
  while (Date.now() - start < opts.gracePeriodMs) {
    const sockets = await io.fetchSockets();
    if (sockets.length === 0) break;
    await new Promise((r) => setTimeout(r, 1000));
  }

  const remaining = await io.fetchSockets();
  for (const socket of remaining) socket.disconnect(true);
  await new Promise<void>((resolve) => io.close(() => resolve()));
}

export class BoundedRoomBuffer<T> {
  private rooms = new Map<string, T[]>();
  constructor(private readonly perRoomLimit: number) {}

  append(roomId: string, item: T): void {
    let list = this.rooms.get(roomId);
    if (!list) { list = []; this.rooms.set(roomId, list); }
    list.push(item);
    if (list.length > this.perRoomLimit) list.shift();
  }

  recent(roomId: string, count?: number): T[] {
    const list = this.rooms.get(roomId);
    if (!list) return [];
    if (!count || count >= list.length) return [...list];
    return list.slice(list.length - count);
  }

  clear(roomId: string): void { this.rooms.delete(roomId); }
  size(roomId: string): number { return this.rooms.get(roomId)?.length ?? 0; }
  totalSize(): number { let n = 0; for (const list of this.rooms.values()) n += list.length; return n; }
}

import crypto from 'crypto';
import { Request, Response, NextFunction } from 'express';

const SKEW_TOLERANCE_SEC = 300;

export function verifyWebhookWithSkew(secret: string) {
  return (req: Request, res: Response, next: NextFunction): void => {
    const ts = req.header('X-Timestamp');
    const sig = req.header('X-Signature');
    if (!ts || !sig) { res.status(400).json({ error: 'MISSING' }); return; }
    const tsNum = Number(ts);
    if (!Number.isFinite(tsNum)) { res.status(400).json({ error: 'BAD_TIMESTAMP' }); return; }
    const now = Math.floor(Date.now() / 1000);
    if (Math.abs(now - tsNum) > SKEW_TOLERANCE_SEC) { res.status(400).json({ error: 'STALE_OR_FUTURE' }); return; }

    const body = req.body instanceof Buffer ? req.body.toString('utf8') : JSON.stringify(req.body ?? {});
    const expected = crypto.createHmac('sha256', secret).update(`${ts}.${body}`).digest('hex');
    const expectedBuf = Buffer.from(expected, 'hex');
    const givenBuf = Buffer.from(sig, 'hex');
    if (expectedBuf.length !== givenBuf.length || !crypto.timingSafeEqual(expectedBuf, givenBuf)) {
      res.status(400).json({ error: 'INVALID_SIGNATURE' });
      return;
    }
    next();
  };
}

export function parseSafeJson(text: string): unknown {
  return JSON.parse(text, (key, value) => {
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') return undefined;
    return value;
  });
}

export function safeMerge<T extends Record<string, unknown>>(target: T, source: Record<string, unknown>): T {
  const out = { ...target };
  for (const key of Object.keys(source)) {
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') continue;
    (out as Record<string, unknown>)[key] = source[key];
  }
  return out;
}

export function nullPrototypeBase<T>(input: T): T {
  if (input === null || typeof input !== 'object') return input;
  if (Array.isArray(input)) return input.map(nullPrototypeBase) as unknown as T;
  const out = Object.create(null) as Record<string, unknown>;
  for (const [key, value] of Object.entries(input as Record<string, unknown>)) {
    if (key === '__proto__' || key === 'constructor' || key === 'prototype') continue;
    out[key] = nullPrototypeBase(value);
  }
  return out as T;
}

import { useEffect, useState } from 'react';

export function useLegacyFetch<T>(url: string, parser: (raw: unknown) => T): { data: T | null; loading: boolean; error: Error | null } {
  const [data, setData] = useState<T | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<Error | null>(null);

  useEffect(() => {
    let cancelled = false;
    setLoading(true);
    setError(null);
    legacyFetch(url)
      .then((raw) => { if (!cancelled) { setData(parser(raw)); setLoading(false); } })
      .catch((e: unknown) => { if (!cancelled) { setError(e instanceof Error ? e : new Error(String(e))); setLoading(false); } });
    return () => { cancelled = true; };
  }, [url, parser]);

  return { data, loading, error };
}

