import { Request, Response } from 'express';
import { UserModel } from './user.model';

export async function streamUsers(req: Request, res: Response): Promise<void> {
  res.setHeader('Content-Type', 'application/x-ndjson');
  const cursor = UserModel.find({}).cursor();
  let aborted = false;
  req.on('close', () => { aborted = true; void cursor.close(); });
  try {
    for await (const user of cursor) {
      if (aborted) break;
      res.write(JSON.stringify(user) + '\n');
    }
    if (!aborted) res.end();
  } catch (err) {
    if (!res.headersSent) res.status(500).json({ error: 'STREAM_FAILED' });
    else res.destroy(err as Error);
  } finally {
    if (!cursor.closed) await cursor.close();
  }
}

