export type Head<T extends ReadonlyArray<unknown>> = T extends readonly [infer H, ...unknown[]] ? H : never;
export type Tail<T extends ReadonlyArray<unknown>> = T extends readonly [unknown, ...infer Rest] ? Rest : [];
export type Last<T extends ReadonlyArray<unknown>> = T extends readonly [...unknown[], infer L] ? L : never;
export type Init<T extends ReadonlyArray<unknown>> = T extends readonly [...infer I, unknown] ? I : [];

export function head<T extends ReadonlyArray<unknown>>(arr: T): Head<T> { return arr[0] as Head<T>; }
export function tail<T extends ReadonlyArray<unknown>>(arr: T): Tail<T> { return arr.slice(1) as unknown as Tail<T>; }

type Args = readonly ['user', 42, true];
type H = Head<Args>;  // 'user'
type T = Tail<Args>;  // [42, true]
type L = Last<Args>;  // true
type I = Init<Args>;  // ['user', 42]

import { Server } from 'socket.io';

export function connectionLogger(io: Server, log: (msg: string, ctx: Record<string, unknown>) => void): void {
  io.use((socket, next) => {
    const ip = socket.handshake.address;
    const transport = socket.conn.transport.name;
    const ua = socket.handshake.headers['user-agent'] ?? '';
    log('socket.connect_attempt', { ip, transport, ua });
    next();
  });
  io.on('connection', (socket) => {
    log('socket.connected', { socketId: socket.id, transport: socket.conn.transport.name });
    socket.on('disconnect', (reason) => {
      log('socket.disconnected', { socketId: socket.id, reason });
    });
  });
}

