export interface SessionStore { destroy(id: string): Promise<void>; }

export function logoutHandler(store: SessionStore, opts: { domain?: string }) {
  return async (req: Request, res: Response): Promise<void> => {
    const sessionId = (req as Request & { sessionId?: string }).sessionId;
    if (sessionId) await store.destroy(sessionId);

    const cookieOpts = { path: '/', domain: opts.domain, secure: true, sameSite: 'strict' as const, httpOnly: true };
    res.clearCookie('connect.sid', cookieOpts);
    res.clearCookie('refresh_token', { ...cookieOpts, path: '/auth' });
    res.clearCookie('csrf', { ...cookieOpts, httpOnly: false });

    res.status(200).json({ ok: true });
  };
}

