import zxcvbn from 'zxcvbn';
import { z } from 'zod';

export class WeakPasswordError extends Error {
  constructor(public readonly suggestions: string[]) { super('PASSWORD_TOO_WEAK'); this.name = 'WeakPasswordError'; }
}

export function validatePasswordStrength(password: string, contextWords: ReadonlyArray<string> = []): void {
  if (password.length < 12) throw new WeakPasswordError(['Use at least 12 characters']);
  const result = zxcvbn(password, contextWords as string[]);
  if (result.score < 3) {
    throw new WeakPasswordError(result.feedback.suggestions);
  }
}

