import express from 'express';

export function userRoutes(): express.Router {
  const router = express.Router();

  router.head('/users/:id', async (req: Request, res: Response): Promise<void> => {
    const exists = await UserModel.exists({ _id: req.params.id });
    if (!exists) { res.status(404).end(); return; }
    res.status(200).end();
  });

  router.get('/users/:id', async (req: Request, res: Response): Promise<void> => {
    const user = await UserModel.findById(req.params.id).select('-passwordHash').lean();
    if (!user) { res.status(404).json({ error: 'NOT_FOUND' }); return; }
    res.json(user);
  });

  return router;
}

