export function describe(value: unknown): string {
  if (value === null) return 'null';
  if (value === undefined) return 'undefined';
  if (typeof value === 'string') return `string: ${value}`;
  if (typeof value === 'number') return Number.isFinite(value) ? `number: ${value}` : `non-finite number`;
  if (typeof value === 'boolean') return `boolean: ${value}`;
  if (typeof value === 'bigint') return `bigint: ${value}`;
  if (typeof value === 'symbol') return `symbol: ${value.toString()}`;
  if (typeof value === 'function') return `function: ${value.name || 'anonymous'}`;
  if (Array.isArray(value)) return `array[${value.length}]`;
  if (value instanceof Date) return `Date: ${value.toISOString()}`;
  if (value instanceof Error) return `Error: ${value.message}`;
  if (value instanceof Map) return `Map[${value.size}]`;
  if (value instanceof Set) return `Set[${value.size}]`;
  return `object: ${Object.keys(value as object).length} keys`;
}

import express from 'express';
import { createServer } from 'http';
import { Server, Socket } from 'socket.io';
import jwt from 'jsonwebtoken';

interface ServerToClient { 'message': (text: string) => void; }
interface ClientToServer { 'echo': (text: string, ack: (res: string) => void) => void; }
interface SocketData { userId: string; }

export function buildServer(opts: { port: number; jwtSecret: string; allowedOrigins: string[] }): { app: express.Express; io: Server<ClientToServer, ServerToClient, Record<string, never>, SocketData> } {
  const app = express();
  const httpServer = createServer(app);
  const io = new Server<ClientToServer, ServerToClient, Record<string, never>, SocketData>(httpServer, {
    cors: { origin: opts.allowedOrigins, credentials: true },
    transports: ['websocket'],
    maxHttpBufferSize: 64 * 1024,
    pingInterval: 25_000,
    pingTimeout: 20_000,
  });

  io.use((socket, next) => {
    const token = (socket.handshake.auth as { token?: string }).token;
    if (!token) return next(new Error('UNAUTHENTICATED'));
    try {
      const payload = jwt.verify(token, opts.jwtSecret, { algorithms: ['HS256'] }) as { sub: string };
      socket.data.userId = payload.sub;
      next();
    } catch { next(new Error('INVALID_TOKEN')); }
  });

  io.on('connection', (socket: Socket<ClientToServer, ServerToClient, Record<string, never>, SocketData>) => {
    socket.on('echo', (text, ack) => ack(`echo: ${text}`));
  });

  httpServer.listen(opts.port);
  return { app, io };
}

