import { useEffect, useRef } from 'react';

export function useInterval(callback: () => void, delayMs: number | null): void {
  const savedCallback = useRef(callback);
  useEffect(() => { savedCallback.current = callback; }, [callback]);

  useEffect(() => {
    if (delayMs === null) return;
    const interval = setInterval(() => savedCallback.current(), delayMs);
    return () => clearInterval(interval);
  }, [delayMs]);
}

interface Logger { fatal(msg: string, ctx: Record<string, unknown>): void; }

export function attachUnhandledRejection(logger: Logger): void {
  process.on('unhandledRejection', (reason, promise) => {
    const err = reason instanceof Error ? reason : new Error(String(reason));
    logger.fatal('unhandled_rejection', { name: err.name, message: err.message, stack: err.stack });
    // For policy: rejection of an internal invariant = crash. External errors that escaped = log + continue.
    // Default to crash since the source is unknown:
    process.exitCode = 1;
  });
}

import crypto from 'crypto';

export function generateUuidV7(): string {
  const ms = BigInt(Date.now());
  const bytes = crypto.randomBytes(16);
  bytes[0] = Number((ms >> 40n) & 0xffn);
  bytes[1] = Number((ms >> 32n) & 0xffn);
  bytes[2] = Number((ms >> 24n) & 0xffn);
  bytes[3] = Number((ms >> 16n) & 0xffn);
  bytes[4] = Number((ms >> 8n) & 0xffn);
  bytes[5] = Number(ms & 0xffn);
  bytes[6] = (bytes[6] & 0x0f) | 0x70;
  bytes[8] = (bytes[8] & 0x3f) | 0x80;
  const hex = bytes.toString('hex');
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20)}`;
}

