});

export function attachClientErrorReports(io: Server, log: (msg: string, ctx: Record<string, unknown>) => void): void {
  io.on('connection', (socket: Socket) => {
    const userId = (socket.data as { userId?: string }).userId;
    socket.on('client:error', (raw: unknown, ack: (ok: boolean) => void) => {
      const parsed = ClientErrorReport.safeParse(raw);
      if (!parsed.success) { ack(false); return; }
      log('client.error', { userId, ...parsed.data });
      ack(true);
    });
  });
}

import { Request, Response, NextFunction } from 'express';

const RESERVED_HEADERS = new Set(['x-user-id', 'x-user-roles', 'x-tenant-id', 'x-internal-user']);

export function stripReservedHeaders(req: Request, _res: Response, next: NextFunction): void {
  for (const header of RESERVED_HEADERS) {
