}

interface VisibilityProps { children: React.ReactNode; show: boolean; mode: 'hide' | 'unmount' | 'placeholder'; }

export function Visibility({ children, show, mode }: VisibilityProps): JSX.Element | null {
  if (show) return <>{children}</>;
  switch (mode) {
    case 'unmount': return null;
    case 'hide': return <div style={{ display: 'none' }} aria-hidden="true">{children}</div>;
    case 'placeholder': return <div className="h-32" aria-hidden="true" />;
  }
}

