export function healthz(_req: Request, res: Response): void {
  res.json({ ok: true, pid: process.pid, uptimeSec: Math.floor(process.uptime()) });
}

export function readyz(mongoConn: typeof mongoose, redis: Redis) {
  return async (_req: Request, res: Response): Promise<void> => {
    const checks: Record<string, { ok: boolean; error?: string }> = {};
    checks.mongo = mongoConn.connection.readyState === 1 ? { ok: true } : { ok: false, error: `state=${mongoConn.connection.readyState}` };
    try { await redis.ping(); checks.redis = { ok: true }; }
    catch (e) { checks.redis = { ok: false, error: e instanceof Error ? e.message : 'unknown' }; }
    const allOk = Object.values(checks).every((c) => c.ok);
    res.status(allOk ? 200 : 503).json({ ok: allOk, checks });
  };
}

