export interface MembershipChange { roomId: string; userId: string; action: 'join' | 'leave'; instanceId: string; }

export class CrossInstanceRoomRegistry {
  private rooms = new Map<string, Set<string>>();
  constructor(private readonly publisher: Redis, private readonly subscriber: Redis, private readonly instanceId: string) {
    void subscriber.subscribe('room:membership');
    subscriber.on('message', (_channel, raw) => {
      try {
        const msg = JSON.parse(raw) as MembershipChange;
        if (msg.instanceId === this.instanceId) return;
        this.applyLocal(msg);
      } catch {}
    });
  }

  async join(roomId: string, userId: string): Promise<void> {
    this.applyLocal({ roomId, userId, action: 'join', instanceId: this.instanceId });
    await this.publisher.publish('room:membership', JSON.stringify({ roomId, userId, action: 'join', instanceId: this.instanceId }));
  }

  async leave(roomId: string, userId: string): Promise<void> {
    this.applyLocal({ roomId, userId, action: 'leave', instanceId: this.instanceId });
    await this.publisher.publish('room:membership', JSON.stringify({ roomId, userId, action: 'leave', instanceId: this.instanceId }));
  }

  private applyLocal(msg: MembershipChange): void {
    let users = this.rooms.get(msg.roomId);
    if (msg.action === 'join') {
      if (!users) { users = new Set(); this.rooms.set(msg.roomId, users); }
      users.add(msg.userId);
    } else {
      users?.delete(msg.userId);
      if (users?.size === 0) this.rooms.delete(msg.roomId);
    }
  }

  members(roomId: string): string[] { return Array.from(this.rooms.get(roomId) ?? []); }
}

