export function ensureUniqueKeys<T extends { id: string }>(items: ReadonlyArray<T>): Array<T & { _renderKey: string }> {
  const seen = new Map<string, number>();
  return items.map((item) => {
    const count = seen.get(item.id) ?? 0;
    seen.set(item.id, count + 1);
    const _renderKey = count === 0 ? item.id : `${item.id}__${count}`;
