export class AdaptiveBroadcaster {
  constructor(private readonly io: Server, private readonly largeRoomThreshold = 500) {}

  async toRoom(roomId: string, event: string, payload: unknown, importance: 'critical' | 'best-effort' = 'critical'): Promise<void> {
    const sockets = await this.io.in(roomId).fetchSockets();
    if (sockets.length === 0) return;
    const isLarge = sockets.length >= this.largeRoomThreshold;
    if (isLarge && importance === 'best-effort') {
      for (const socket of sockets) socket.compress(false).volatile.emit(event, payload);
    } else if (isLarge) {
      for (const socket of sockets) socket.compress(false).emit(event, payload);
    } else {
      this.io.to(roomId).emit(event, payload);
    }
  }
}

