export function flattenCauses(err: unknown): Array<{ name: string; message: string; stack?: string }> {
  const chain: Array<{ name: string; message: string; stack?: string }> = [];
  let current: unknown = err;
  let depth = 0;
  while (current instanceof Error && depth < 10) {
    chain.push({ name: current.name, message: current.message, stack: current.stack });
    const next = (current as Error & { cause?: unknown }).cause;
    current = next;
    depth++;
  }
  return chain;
}

