export async function processAllEvents(batchSize = 500, onBatch: (events: Event[]) => Promise<void>): Promise<{ processed: number }> {
  const cursor = EventBigModel.find({}).lean<Event[]>().cursor({ batchSize });
  let processed = 0;
  let batch: Event[] = [];
  for await (const event of cursor) {
    batch.push(event);
    if (batch.length >= batchSize) {
      await onBatch(batch);
      processed += batch.length;
      batch = [];
    }
  }
  if (batch.length > 0) { await onBatch(batch); processed += batch.length; }
  return { processed };
}

