import type { Socket } from 'socket.io-client';

export function useConnectionToast(socket: Socket): JSX.Element | null {
  const [status, setStatus] = useState<'connected' | 'reconnecting' | 'offline'>(socket.connected ? 'connected' : 'reconnecting');

  useEffect(() => {
    const onConnect = (): void => setStatus('connected');
    const onDisconnect = (reason: Socket.DisconnectReason): void => {
      setStatus(reason === 'io client disconnect' || reason === 'io server disconnect' ? 'offline' : 'reconnecting');
    };
    const onAttempt = (): void => setStatus('reconnecting');
    const onFailed = (): void => setStatus('offline');
    socket.on('connect', onConnect);
    socket.on('disconnect', onDisconnect);
    socket.io.on('reconnect_attempt', onAttempt);
    socket.io.on('reconnect_failed', onFailed);
    return () => {
      socket.off('connect', onConnect);
      socket.off('disconnect', onDisconnect);
      socket.io.off('reconnect_attempt', onAttempt);
      socket.io.off('reconnect_failed', onFailed);
    };
  }, [socket]);

  if (status === 'connected') return null;
  return (
    <div className="fixed top-4 left-1/2 -translate-x-1/2 px-4 py-2 rounded bg-yellow-100 text-yellow-900 text-sm shadow">
      {status === 'reconnecting' ? 'Reconnecting…' : 'Offline'}
    </div>
  );
}

