export function chunk<T>(items: ReadonlyArray<T>, size: number): T[][] {
  if (size <= 0) throw new Error('SIZE_MUST_BE_POSITIVE');
  const out: T[][] = [];
  for (let i = 0; i < items.length; i += size) out.push(items.slice(i, i + size));
  return out;
}

export function uniqueBy<T, K>(items: ReadonlyArray<T>, key: (item: T) => K): T[] {
  const seen = new Set<K>();
  const out: T[] = [];
  for (const item of items) {
    const k = key(item);
    if (seen.has(k)) continue;
    seen.add(k);
    out.push(item);
  }
  return out;
}

