export function attachBinaryHandler(io: Server, onPayload: (socket: Socket, payload: Buffer) => void): void {
  io.on('connection', (socket: Socket) => {
    socket.on('binary:payload', (raw: ArrayBuffer | Buffer) => {
      const buf = Buffer.isBuffer(raw) ? raw : Buffer.from(raw);
      if (buf.length === 0 || buf.length > 1024 * 1024) { socket.emit('error', { code: 'INVALID_SIZE' }); return; }
      onPayload(socket, buf);
    });
  });
}

