export interface UserLoader { load(userId: string): Promise<{ exists: boolean; suspended: boolean } | null>; }

export function attachUserValidation(io: Server, loader: UserLoader): void {
  io.use(async (socket, next) => {
    const userId = (socket.handshake.auth as { userId?: string }).userId;
    if (!userId) return next(new Error('NO_USER'));
    const start = Date.now();
    const user = await loader.load(userId);
    if (Date.now() - start > 1000) console.warn(`[io.use] slow loader: ${Date.now() - start}ms`);
    if (!user || !user.exists) return next(new Error('UNKNOWN_USER'));
    if (user.suspended) return next(new Error('SUSPENDED'));
    (socket.data as { userId: string }).userId = userId;
    next();
  });
}

