interface Logger { error(msg: string, ctx: Record<string, unknown>): void; }

export function noStackInProd(logger: Logger, isProd: boolean): ErrorRequestHandler {
  return (err: unknown, req: Request, res: Response, _next: NextFunction): void => {
    const e = err as Error;
    logger.error('error', { name: e.name, message: e.message, stack: e.stack, path: req.path });
    res.status(500).json({
      error: { code: 'INTERNAL', message: isProd ? 'An unexpected error occurred' : e.message, stack: isProd ? undefined : e.stack },
    });
  };
}

