export async function fetchPreferred(url: string, ms: number): Promise<Response> {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), ms);
  try { return await fetch(url, { signal: controller.signal }); }
  finally { clearTimeout(timer); }
}

export async function fetchLegacy(url: string, ms: number): Promise<Response> {
  const timeoutPromise = new Promise<Response>((_, reject) => setTimeout(() => reject(new Error('TIMEOUT')), ms));
  return Promise.race([fetch(url), timeoutPromise]);
}

