export function sortedCopy<T>(items: ReadonlyArray<T>, cmp: (a: T, b: T) => number): T[] {
  return [...items].sort(cmp);
}

export function topN<T>(items: ReadonlyArray<T>, n: number, key: (item: T) => number): T[] {
  if (n <= 0) return [];
  return sortedCopy(items, (a, b) => key(b) - key(a)).slice(0, n);
}

