export class QueryBuilder {
  private filters: Array<{ field: string; op: string; value: unknown }> = [];
  private sortBy: { field: string; dir: 'asc' | 'desc' } | null = null;
  private limitTo = 50;

  where(field: string, op: string, value: unknown): this {
    this.filters.push({ field, op, value });
    return this;
  }
  orderBy(field: string, dir: 'asc' | 'desc' = 'asc'): this {
    this.sortBy = { field, dir };
    return this;
  }
  limit(n: number): this {
    if (n <= 0) throw new Error('LIMIT_POSITIVE');
    this.limitTo = n;
    return this;
  }
  build(): { filters: Array<{ field: string; op: string; value: unknown }>; sort: { field: string; dir: 'asc' | 'desc' } | null; limit: number } {
    return { filters: [...this.filters], sort: this.sortBy, limit: this.limitTo };
  }
}

