export type CallOutcome<T> = { ok: true; value: T } | { ok: false; reason: 'timeout' | 'error'; message?: string };

async function withTimeout<T>(p: Promise<T>, ms: number): Promise<{ ok: true; value: T } | { ok: false; reason: 'timeout' }> {
  return new Promise((resolve) => {
    const timer = setTimeout(() => resolve({ ok: false, reason: 'timeout' }), ms);
    p.then((value) => { clearTimeout(timer); resolve({ ok: true, value }); }, () => { clearTimeout(timer); resolve({ ok: false, reason: 'timeout' }); });
  });
}

export async function fanOutWithTimeouts<T>(tasks: ReadonlyArray<() => Promise<T>>, ms: number): Promise<CallOutcome<T>[]> {
  const wrapped = tasks.map(async (task): Promise<CallOutcome<T>> => {
    try {
      const result = await withTimeout(task(), ms);
      if (result.ok) return result;
      return { ok: false, reason: 'timeout' };
    } catch (e) {
      return { ok: false, reason: 'error', message: e instanceof Error ? e.message : String(e) };
    }
  });
  return Promise.all(wrapped);
}

