import { useRef, useState, useEffect } from 'react';

export function ScrollDistance(): JSX.Element {
  const totalScrolledRef = useRef(0);
  const lastY = useRef(window.scrollY);
  const [showHint, setShowHint] = useState(true);

  useEffect(() => {
    const onScroll = (): void => {
      const delta = Math.abs(window.scrollY - lastY.current);
      lastY.current = window.scrollY;
      totalScrolledRef.current += delta;
      if (totalScrolledRef.current > 1000 && showHint) setShowHint(false);
    };
    window.addEventListener('scroll', onScroll);
    return () => window.removeEventListener('scroll', onScroll);
  }, [showHint]);

  return showHint ? <div className="fixed bottom-4 right-4">Keep scrolling</div> : null;
}

