export function friendly(issue: ZodIssue): string {
  if (issue.code === 'too_small' && issue.path[0] === 'password') return 'Password must be at least 12 characters';
  if (issue.code === 'invalid_string' && issue.path[0] === 'email') return 'Enter a valid email address';
  return DEFAULT_MESSAGES[issue.code] ?? issue.message;
}

import { ZodError } from 'zod';

export function flattenFriendly(error: ZodError): Record<string, string[]> {
  const out: Record<string, string[]> = {};
  for (const issue of error.issues) {
    const key = issue.path.join('.') || '_form';
    (out[key] ??= []).push(friendly(issue));
  }
  return out;
}

