import { Server } from 'socket.io';

export function attachAuth(io: Server, getUserId: (token: string) => string | null): void {
  io.use((socket, next) => {
    const token = (socket.handshake.auth as { token?: string }).token;
    if (!token) {
      const err = new Error('UNAUTHENTICATED') as Error & { data?: unknown };
      err.data = { code: 'NO_TOKEN', hint: 'Provide token in handshake.auth.token' };
      return next(err);
    }
    const userId = getUserId(token);
    if (!userId) {
      const err = new Error('UNAUTHENTICATED') as Error & { data?: unknown };
      err.data = { code: 'INVALID_TOKEN' };
      return next(err);
    }
    (socket.data as { userId: string }).userId = userId;
    next();
  });
}

