const ClientError = z.object({
  message: z.string().min(1).max(1000),
  stack: z.string().max(5000).optional(),
  url: z.string().max(2048).optional(),
});

interface ErrorReporter { report(args: { userId: string; message: string; stack?: string; url?: string }): void; }

export function mountClientErrorReporter(io: Server, reporter: ErrorReporter): void {
  io.on('connection', (socket: Socket) => {
    let countThisMinute = 0;
    let windowStart = Date.now();

    socket.on('client:error', (raw: unknown) => {
      const now = Date.now();
      if (now - windowStart > 60_000) { countThisMinute = 0; windowStart = now; }
      countThisMinute++;
      if (countThisMinute > 30) return;

      const parsed = ClientError.safeParse(raw);
      if (!parsed.success) return;
      const userId = (socket.data as { userId?: string }).userId ?? 'anon';
      reporter.report({ userId, ...parsed.data });
    });
  });
}

export function fingerprint(secret: string): string {
  if (secret.length < 12) return '****';
  return `${secret.slice(0, 4)}...${secret.slice(-4)}`;
}

export function safeLogConfig(config: Record<string, string>, secretKeys: ReadonlyArray<string>): Record<string, string> {
  const out: Record<string, string> = {};
  const secretSet = new Set(secretKeys.map((k) => k.toLowerCase()));
  for (const [key, value] of Object.entries(config)) {
    if (secretSet.has(key.toLowerCase())) out[key] = fingerprint(value);
    else out[key] = value;
  }
  return out;
}

