export class AsyncMutex {
  private chain: Promise<unknown> = Promise.resolve();

  async lock<T>(work: () => Promise<T>): Promise<T> {
    const previous = this.chain;
    let release: () => void = () => {};
    this.chain = new Promise<void>((resolve) => { release = resolve; });
    try {
      await previous;
      return await work();
    } finally {
      release();
    }
  }
}

export class KeyedMutex {
  private mutexes = new Map<string, AsyncMutex>();
  async lock<T>(key: string, work: () => Promise<T>): Promise<T> {
    let m = this.mutexes.get(key);
    if (!m) { m = new AsyncMutex(); this.mutexes.set(key, m); }
    try { return await m.lock(work); }
    finally { /* keep mutex around — small map */ }
  }
}
